script:
frappe.ui.form.on('Making Charge Price', {
	refresh(frm) {
    	var fields = [['custom_category', 'Item Category']];
    	set_item_attribute_filters_in_sub_category(frm, fields, 'subcategory');

	}
});


function set_item_attribute_filters_in_sub_category(frm, fields, child_table) {
	fields.map(function(field) {
		frm.set_query(field[0], child_table, function() {
			return { 
    			query: 'jewellery_erpnext.query.item_attribute_query',
				filters: {'item_attribute': field[1]}
			};
    	});
	});
}


frappe.ui.form.on('Making Charge Price Item Subcategory', {
	subcategory: function (frm, cdt, cdn) {
	    var d = locals[cdt][cdn];
	    frappe.db.get_value("Attribute Value", {'name': d.subcategory}, "parent_attribute_value", (r) => {
	        console.log(r)
	        {
				frappe.model.set_value(cdt, cdn, "custom_category", r.parent_attribute_value);
	        }
			});
		refresh_field("subcategory");
	}     
});

frappe.ui.form.on('Order Form', {
    onload(frm) {
        update_totals(frm);
    },

    after_save(frm) {
        update_totals(frm);
    },
	setup(frm) {

	    frm.set_query("salesman_name", function() {
			return {
				filters: [
					["Sales Person","parent_sales_person", "=", "Sales Team"],
					["Sales Person","is_group", "=", "0"],
				]
			}
		});

		frm.set_query('metal_type', 'order_details', function (doc, cdt, cdn) {
			let d = locals[cdt][cdn];
			return {
				filters: [
					['Attribute Value', 'attribute_value', 'in', 'Gold, Silver, Platinum'],
				]
			};
		});

		// filter for sub setting 2
		frm.set_query('sub_setting_type2', 'order_details', function (doc, cdt, cdn) {
			let d = locals[cdt][cdn];
			return {
				filters: {
					'parent_attribute_value': d.setting_type
				}
			};
		});

		 var fields = [
		     ['sizer_type','Sizer Type'],
		     ['stone_changeable', 'Stone Changeable'],
		     ['detachable','Detachable'],
		     ['diamond_type','Diamond Type'],
		     ['gemstone_type1','Gemstone Type'],
		     ['metal_target_from_range','Metal Target Range'],
		     ['diamond_target_from_range','Diamond Target Range'],
		     ]
		 set_filters_on_child_table_fields(frm, fields);

		 frm.set_query('design_type', 'order_details', function (doc, cdt, cdn) {
			let d = locals[cdt][cdn];
			if(d.design_by == "Customer Design"){
    			return {
    				filters: [
    					["Attribute Value", "attribute_value", "in", "New Design,Sketch Design"],
    				]
    			};
			} 
			else{
			    return {
    				query: 'jewellery_erpnext.query.item_attribute_query',
    				filters: { 'item_attribute': "Design Type" }
    			};
			}
		});


	},

	refresh(frm) {
  		if(cur_frm.doc.workflow_state == 'Send For Approval'){
		    cur_frm.fields_dict['order_details'].grid.wrapper.find('.grid-add-row').hide();
	    }
	    frm.fields_dict.order_details.grid.toggle_enable('design_id', frm.doc.workflow_state !== 'Approved');
	},

	onload(frm){
	    if (frm.doc.__islocal) {
    	    frappe.db.get_value("Employee",{"user_id": frappe.session.user}, ["company","branch","department"], (r)=> {
    	        if (r.branch){
    	            frm.set_value("branch", r.branch);
    	            frm.set_df_property('branch', 'read_only',1);
    	            frm.set_value("department", r.department);
    	            frm.set_df_property('department', 'read_only',1);
    	            frm.set_value("company", r.company);
    	            frm.set_df_property('company', 'read_only',1);
    	        }
    	    })
	    }

	},

	custom_cad_finish_date(frm) {
		validate_dates(frm, frm.doc, "custom_cad_finish_date")
		calculate_due_days(frm);
	},

	custom_cad_finish_days (frm) {
		delivery_date(frm);
	},

	validate (frm) {
		if (frm.doc.custom_cad_finish_date < frm.doc.order_date) {
			frappe.msgprint(__("You can not select past date in CAD Finish Date"));
			frappe.validated = false;
		}
	},

	diamond_quality(frm){
	    update_fields_in_child_table(frm, "diamond_quality")
	},
	order_type(frm){
	    if(frm.doc.order_type=='Sales' && frm.doc.customer_code != 'MHCU0012'){
			frm.set_value("flow_type", "MTO");
			frm.set_df_property("flow_type", "read_only", 1);
		}
		else if(frm.doc.order_type=='Stock Order' && frm.doc.customer_code != 'MHCU0012'){
			frm.set_value("flow_type", "FILLER");
			frm.set_df_property("flow_type", "read_only", 1);
		}
		else if(frm.doc.order_type=='Purchase' && frm.doc.customer_code != 'MHCU0012'){
			frm.set_value("flow_type", "FILLER");
			frm.set_df_property("flow_type", "read_only", 1);
		}
		else{
			frm.set_df_property("flow_type", "read_only", 0);
		}
	}
})

frappe.ui.form.on('Order Form Detail', {
	chain_type(frm,cdt,cdn) {
        var row = locals[cdt][cdn];
        // console.log(row.chain_type)
        if(row.chain_type == 'No'){
	        frappe.model.set_value(row.doctype, row.name, 'chain_length', '0');
        }
	},

	setting_type(frm,cdt,cdn) {
        var row = locals[cdt][cdn];
	    frappe.model.set_value(row.doctype, row.name, 'sub_setting_type1', '');
	    frappe.model.set_value(row.doctype, row.name, 'sub_setting_type2', '');
	    if(row.setting_type == 'Close'){ 
    	    row.metal_touch = "22KT";
    	    row.metal_colour = "Yellow";
	    }
	    if(row.setting_type == 'Open'){ 
    	    row.metal_touch = "18KT";
	    }
	    refresh_field("order_details");
	},

// 	sub_setting_type1(frm,cdt,cdn) {
//         var row = locals[cdt][cdn];
//         if(row.sub_setting_type1 == 'Close Setting'){ 
//     	    row.metal_touch = "22KT";
//     	    row.metal_colour = "Yellow";
// 	    }
// 	},

	order_details_add(frm, cdt, cdn){
        var row = locals[cdt][cdn];
        row.custom_parcel_place = frm.doc.parcel_place;
        row.custom_service_type = frm.doc.service_type;
        refresh_field("order_details");
    },

     category(frm,cdt,cdn){
        var row = locals[cdt][cdn];

        let scale = ['Earrings', 'Pendant', 'Necklace', 'Mangalsutra', 'Mugappu', 'Nose Pin', 'Waistband', 'Armlet', 'Head Accessories', 'Accessories'];
        if(scale.includes(row.category)){
                row.sizer_type = 'Scale'
        }

        if(row.category == 'Bangles'){
            row.sizer_type = 'Anna'
        }

        if(row.category == 'Ring'){
            row.sizer_type = 'Rod'
        }

        if(row.category == 'Bracelet'){
    		frm.set_query('sizer_type', 'order_details', function(doc,cdt,cdn) {
    			return { 
    				filters: [
    				    ["Attribute Value", "name", "in", ["Anna","Scale"]]    
    				]
    			};
        	});
        }

        refresh_field("order_details");
    },
})

function set_filters_on_child_table_fields(frm, fields) {
    fields.map(function(field){
        frm.set_query(field[0], "order_details", function() {
            return {
                query: 'jewellery_erpnext.query.item_attribute_query',
                filters: {'item_attribute': field[1]}
            };
        });
    });
}

function calculate_due_days(frm) {
	frm.set_value('custom_cad_finish_days', frappe.datetime.get_day_diff(frm.doc.custom_cad_finish_date, frm.doc.order_date));
}

function validate_dates(frm, doc, dateField) {
    let order_date = frm.doc.order_date
    if (doc[dateField] < order_date) {
        frappe.model.set_value(doc.doctype, doc.name, dateField, frappe.datetime.add_days(order_date,1))
    }
}

function delivery_date(frm) {
	frm.set_value('custom_cad_finish_date', frappe.datetime.add_days(frm.doc.order_date, frm.doc.custom_cad_finish_days));
}

function update_fields_in_child_table(frm, fieldname) {
	$.each(frm.doc.order_details || [], function (i, d) {
		d[fieldname] = frm.doc[fieldname];
	});
	refresh_field("order_details");
}

function set_item_code_readonly(frm) {
    frm.fields_dict.order_details.grid.get_field('design_id').df.read_only = (frm.doc.workflow_state === 'Approved');
    frm.fields_dict.order_details.grid.refresh();
}

frappe.ui.form.on('Order Form Detail', {
    add(frm, cdt, cdn) {
        update_totals(frm);
    },
    remove(frm, cdt, cdn) {
        update_totals(frm);
    },
    qty(frm, cdt, cdn) {
        update_totals(frm);
    }
});

function update_totals(frm) {
    const rows = frm.doc.order_details || [];

    // Count total rows
    frm.set_value('total_rows', rows.length);

    // Sum qty from each row
    const total_qty = rows.reduce((sum, row) => {
        return sum + (parseFloat(row.qty) || 0);
    }, 0);

    frm.set_value('total_no_of_designs', total_qty);
}

frappe.ui.form.on('BOM', {
	refresh(frm) {

	    // 	filter for metal purity according to metal touch in BOM Finding Deatil
		frm.set_query('metal_purity', 'finding_detail', function (doc, cdt, cdn) {
			let d = locals[cdt][cdn];
			return {
				filters: {
					'is_metal_purity': 1,
					'metal_touch':d.metal_touch
				}
			};
		});

		// 	filter for finding subcategory according to finding category in BOM Finding Deatil
		frm.set_query('finding_type', 'finding_detail', function (doc, cdt, cdn) {
			let d = locals[cdt][cdn];
			return {
				filters: {
					'is_finding_type': 1,
					'parent_attribute_value':d.finding_category
				}
			};
		});

        // 	filter for metal purity according to metal touch in BOM Metal Deatil
		frm.set_query('metal_purity', 'metal_detail', function (doc, cdt, cdn) {
			let d = locals[cdt][cdn];
			return {
				filters: {
					'is_metal_purity': 1,
					'metal_touch':d.metal_touch
				}
			};
		});

		frm.set_query('item_code', 'other_detail', function (doc, cdt, cdn) {
			let d = locals[cdt][cdn];
			return {
				filters: [
				    ["Item", "variant_of", "=", "O"]    
				]
			};
		});


	},
	navratna(frm){
		if (cur_frm.doc.navratna == 1){
		    frm.get_field('gemstone_detail').grid.cannot_delete_rows = true;

            // Hiding the grid remove icons
            $('*[data-fieldname="gemstone_detail"] .grid-remove-rows').hide();
            $('*[data-fieldname="gemstone_detail"] .grid-remove-all-rows').hide();
            $('*[data-fieldname="gemstone_detail"] .grid-delete-row').hide();

			const arr = ["Ruby","Pearl","Coral","Emerald","Yellow Shappire","Blue Shappire","Hessonite","Cat's Eye"]
			var arrayLength = arr.length;
			for (var i = 0; i < arrayLength; i++) {
				let row = frm.add_child('gemstone_detail', {
					gemstone_type: arr[i],
					navratna:'navratna'
				});
			}
			frm.refresh_field('gemstone_detail');
		}	
		if(cur_frm.doc.navratna == 0){
			const arr = ["Ruby","Pearl","Coral","Emerald","Yellow Shappire","Blue Shappire","Hessonite","Cat's Eye"]
			var tbl = cur_frm.doc.gemstone_detail || [];
			var i = tbl.length;
			while (i--)
			{	

				if(tbl[i].navratna == 'navratna')
				{
					cur_frm.get_field("gemstone_detail").grid.grid_rows[i].remove();
				}
			}
			cur_frm.refresh();
		}
	},
})

