frappe.ui.form.on('Item', {
	setup: function(frm) {
        var parent_fields = [
            ['item_category','Item Category'],
                             ['item_subcategory','Item Subcategory'],
                             ['setting_type','Setting Type'],
                             ['product_usage','Product Usage'],
                             ['product_shape','Product Shape'],
                             ['item_product_size', 'Product Size'],
                             ['item_length', 'Length'],
                             ['item_height', 'Height'],
                             ['sizer_type', 'Sizer Type'],
                             ['stone_changeable', 'Stone Changeable'],
                             ['vanki_type', 'Vanki Type'],
                             ['sub_setting_type', 'Sub Setting Type'],
                             ['item_total_mugappu', 'Total Mugappu'],
                             ['custom_reason_for_design_code_','Mod Reason'],
                             ['version_type','Item Version'],];
        set_item_attribute_filters_on_fields_in_parent_doctype(frm, parent_fields);

        frm.set_query('sub_setting_type',function(doc) {
            return{
                filters: {
                    'parent_attribute_value' : cur_frm.doc.setting_type
                }
            };
        });

        frm.set_query('item_subcategory',function(doc) {
            return{
                filters: {
                    'parent_attribute_value' : cur_frm.doc.item_category
                }
            };
        });

        frm.set_query("modified_from", function(){
            return {
                "filters": [
                    ["Item", "is_design_code", "=", 1],
                ]
            }
    });

        frm.set_query("master_bom", function() {
			return {
				filters: [
					["BOM","item", "=", frm.doc.name]
				]
			}
		});

		frm.set_query("tag_no", function() {
			return {
				filters: [
					["Serial No","item_code", "=", frm.doc.name]
				]
			}
		});

        set_item_attribute_filters_in_similar_item_fields(frm);
		set_item_attribute_filters_in_set_item_fields(frm);
		set_item_attribute_filters_in_sufix_item_fields(frm);

		var design = [
            ['custom_age_group', 'Age Group'],
            ['custom_alphabetnumber', 'Alphabet/Number'],
            ['custom_animalbirds', 'Animal/Birds'], 
            ['custom_collection', 'Collection'],
            ['custom_design_style', 'Design Style'],
            ['custom_gender', 'Gender'],
            ['custom_lines__rows', 'Lines & Rows'],
            ['custom_language', 'Language'],
            ['custom_occasion', 'Occasion'],
            ['custom_rhodium', 'Rhodium'],
            ['custom_religious', 'Religious'],
            ['custom_shapes', 'Shapes'], 
            ['custom_zodiac', 'Zodiac'],
        ];

		set_filters_on_design_fields(frm, design);
    },
    onload: function(frm) {
	    if (frm.doc.item_name == ''){
    	    if(frm.doc.item_category_code && frm.doc.variant_of){
        		frappe.db.get_value("Item", frm.doc.variant_of, "name", (r)=> {
        	        if (r.name)   frm.set_value("item_code", r.name)
        	    })
    	    }
	    }
	    if(frm.doc.variant_of && frm.doc.item_code){
	        const consumables = ["Design DNU","Chemicals", "Machinery", "Office Supplies", "Electric Accessories", "Wax", "Spare Accessories", "Stationery", "Medical Supplies", "Tools & Accessories"]
	        if (frm.doc.variant_of == 'M' || frm.doc.variant_of == 'ML' || frm.doc.variant_of == 'D' || frm.doc.variant_of == 'DL' || frm.doc.variant_of == 'DBK' || frm.doc.variant_of == 'G' || frm.doc.variant_of == 'GL' || frm.doc.variant_of == 'F' || frm.doc.variant_of == 'FL' || frm.doc.variant_of == 'O' || frm.doc.variant_of == 'OL'){
    	       var item_group = frm.doc.item_group.replace(" - T", " - V")
    	        frm.set_value("item_group",item_group)
    	    }
    	    else{
    	         if(consumables.includes(frm.doc.item_group)==1){
        	        console.log("consumables")
        	    }
        	    else{
        	        frm.set_value("item_group",frm.doc.item_subcategory + ' - V')
        	    }
    	    }
	    }
	},
	item_category_code: function(frm) {
		frappe.call({
            method: 'get_max_number',
            args: {
                'item_category_code': frm.doc.item_category_code,
            },
            callback: function(r) {
                if (!r.exc) {
                        frm.set_value('item_code',r.message[1])
                        frm.set_value('sequence',r.message[0])
                    if(frm.doc.modified_from == ''){
                    }
                }
            }
        });
	},
	item_subcategory: function(frm) {
	   // frm.set_value('item_group',frm.doc.item_subcategory + ' - V')
		if (frm.doc.variant_of && frm.doc.item_group != 'Design DNU'){
		    frm.set_value('item_group',frm.doc.item_subcategory + ' - V')
		}
		else{
		    frm.set_value('item_group',frm.doc.item_subcategory + ' - T')
		}
	},
});

function set_item_attribute_filters_on_fields_in_parent_doctype(frm, fields) {
  fields.map(function(field){
    frm.set_query(field[0], function() {
      return {
        query: 'jewellery_erpnext.query.item_attribute_query',
        filters: {'item_attribute': field[1]}
      };
    });
  });
}

function set_filters_on_child_table_fields(frm, fields, child_table) {
    fields.map(function(field){
        frm.set_query(field[0], child_table, function() {
            return {
                query: 'jewellery_erpnext.query.item_attribute_query',
                filters: {'item_attribute': field[1]}
            };
        });
    });
}

function set_item_attribute_filters_in_similar_item_fields(frm) {
	var fields = [  ['reason', 'Mod Reason'] ];
	set_item_attribute_filters_in_bom_detail_fields(frm, fields, 'custom_similar_item_table');
}

function set_item_attribute_filters_in_set_item_fields(frm) {
	var fields = [  ['reason', 'Mod Reason'] ];
	set_item_attribute_filters_in_bom_detail_fields(frm, fields, 'custom_set_item_table');
}

function set_item_attribute_filters_in_sufix_item_fields(frm) {
	var fields = [  ['reason', 'Mod Reason'] ];
	set_item_attribute_filters_in_bom_detail_fields(frm, fields, 'custom_sufix_item_table');
}

function set_item_attribute_filters_in_bom_detail_fields(frm, fields, child_table) {
	fields.map(function(field) {
		frm.set_query(field[0], child_table, function() {
			return { 
    			query: 'jewellery_erpnext.query.item_attribute_query',
				filters: {'item_attribute': field[1]}
			};
    	});
	});
}

function set_filters_on_design_fields(frm, design) {
    design.map(function(design){
        frm.set_query(design[0], function() {
            return {
                filters: [ ['Attribute Value', 'parent_attribute_value', '=', design[1] ],                ]
            };
        });
    });
}

frappe.ui.form.on("Employee Penalty", {
    refresh(frm) {        
        calculate_total(frm);
    },
});

frappe.ui.form.on("Employee Penalty Detail", {
    penalty_amount(frm, cdt, cdn) {
        calculate_total(frm);
    },
});

function calculate_total(frm) {
    let total_penalty_amount = 0;

    if (frm.doc.penalty_type) {
        frm.doc.penalty_type.forEach(function (d) {
            total_penalty_amount += d.penalty_amount;
            // console.log(total_penalty_amount)
        });
    }

