//private function to show single child table field
function show_field(frm, field_name) {
    show_hide_field(frm,field_name, 0);
}

// //private function to show or hide multiple child table fields
function show_hide_fields(frm, fields, hidden){
    fields.map(function(field){
        show_hide_field(frm,field, hidden);
    });
}

//private function to show or hide single child table fields
function show_hide_field(frm, field, hidden){
    var df = frappe.meta.get_docfield(frm.doc.doctype, field.toLowerCase().replace(/\s+/g, '_'), frm.doc.name);
    if (df) {
        df.hidden = hidden;
        if (df.hidden===0) df.reqd = 0;
    }
    frm.refresh_fields();
}
//public function to show item attribute fields based on the selected subcategory
function show_attribute_fields_for_subcategory(frm) {
    if (frm.doc.item_subcategory){
        frappe.model.with_doc("Attribute Value", frm.doc.item_subcategory, function(r) {
			var subcategory_attribute_value = frappe.model.get_doc("Attribute Value", frm.doc.item_subcategory);
			if(subcategory_attribute_value.is_subcategory == 1){
			    if (subcategory_attribute_value.item_attributes){
                    $.each(subcategory_attribute_value.item_attributes, function(index, row) {
					    show_field(frm, row.item_attribute);
                    });
			    }
			}
		});
    }
}

