                filters: {
                    user_id: frappe.session.user
                },
                fieldname: ["branch", "company"]
            },
            callback: function (r) {
                if (r.message) {
                    let employee_branch = r.message.branch; // Branch from Employee record
                    let employee_company = r.message.company; // Company from Employee record

                    // Apply filter to the Branch field
                    frm.set_query('custom_branch', function () {
                        return {
                            filters: {
                                name: employee_branch
                            }
