frappe.ui.form.on('Full and Final Statement', {
    employee: function(frm) {
        if (frm.doc.employee) {
            frm.fields_dict['payables'].grid.get_field('reference_document_type').get_query = function() {
                return {
                    filters: [
                        ["name", "in", ["Gratuity", "Expense Claim", "Additional Salary", "Leave Encashment"]]
                    ]
                };
            };

            frm.fields_dict['receivables'].grid.get_field('reference_document_type').get_query = function() {
                return {
                    filters: [
                        ["name", "in", ["Employee Advance"]]
                    ]
                };
            };

            frm.doc.payables.forEach(child => {
                if (["Gratuity", "Expense Claim", "Additional Salary", "Leave Encashment"].includes(child.reference_document_type)) {
                    let doctypeToFetch = child.reference_document_type; // Determine which doctype to fetch

                    frappe.call({
                        method: "frappe.client.get_list",
                        args: {
                            doctype: doctypeToFetch,
                            filters: {
                                employee: frm.doc.employee,
                                docstatus: 1 
                            },
                            fields: ["name"],
                            order_by: "creation desc", 
                            limit_page_length: 1
                        },
                        callback: function(response) {
                            if (response.message && response.message.length > 0) {
                                frappe.model.set_value(child.doctype, child.name, "reference_document", response.message[0].name);
                            }
                        }
                    });
                }
            });

            frm.doc.receivables.forEach(child => {
                if (child.reference_document_type === "Employee Advance") {
                    let doctypeToFetch = "Employee Advance"; // Static for Employee Advance

                    frappe.call({
                        method: "frappe.client.get_list",
                        args: {
                            doctype: doctypeToFetch,
                            filters: {
                                employee: frm.doc.employee,
                                docstatus: 1  
                            },
                            fields: ["name", "advance_amount"], 
                            order_by: "creation desc", 
                            limit_page_length: 1
                        },
                        callback: function(response) {
                            if (response.message && response.message.length > 0) {
                                frappe.model.set_value(child.doctype, child.name, "reference_document", response.message[0].name);
                            }
                        }
                    });
                }
            });
        }
    }
});

