function set_filters_on_parent_table_fields(frm, fields) {
	fields.map(function (field) {
		frm.set_query(field[0], function (doc) {
			return {
				query: 'jewellery_erpnext.query.item_attribute_query',
				filters: { 'item_attribute': field[1], "customer_code": doc.customer }
			};
		});
	});
}

function set_filters_on_child_table_fields(frm, fields) {
	fields.map(function (field) {
		frm.fields_dict[field.child_table].grid.get_field(field.fieldname).get_query = function (doc, cdt, cdn) {
			let row = locals[cdt][cdn]; // Get the row in the child table
			return {
				query: 'jewellery_erpnext.query.item_attribute_query',
				filters: { 'item_attribute': field.attribute, "customer_code": frm.doc.customer }
			};
		};
	});
}

