function update_totals(frm) {
    const rows = frm.doc.order_details || [];

    frm.set_value('total_rows', rows.length);

    const total_qty = rows.reduce((sum, row) => {
        return sum + (parseFloat(row.qty) || 0);
    }, 0);

    frm.set_value('total_no_of_designs', total_qty);
}
